  ARRAY['Cruise Passenger Friendly', 'Port-Based Smart Routing', 'Return-To-Ship Focused']::text[],
  'https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp',
  'https://api.cdn.visitjeju.net/photomng/thumbnailpath/202409/20/b9661064-af2f-4197-aef0-d3d44bf6c2b5.webp',
  'A shore excursion bus tour for cruise guests arriving at either Jeju Port or Seogwipo Gangjeong Cruise Port. The east route focuses on Jeju’s UNESCO and heritage icons, while the south route favors mountain views, cliffs, waterfalls, and a traditional market finish.',
  'Jeju Cruise Shore Excursion Bus Tour | East or South Route by Port | AtoC Korea',
  'A Jeju shore excursion bus tour designed for cruise passengers. Route changes by docking port: Jeju Port guests visit Seongsan Ilchulbong, Seopjikoji, Seongeup Folk Village, and Dongmun Market, while Gangjeong Port guests visit 1100 Highland, Jusangjeolli Cliff, Cheonjiyeon Falls, and Seogwipo Olle Market.',
  'Jeju Cruise Shore Excursion',
  'East or South Route by Port',
  '59',
  'USD',
  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"jeju-cruise-shore-excursion-bus-tour","locale":"zh-TW","product_id":"jeju-cruise-shore-excursion-bus-tour","seo":{"pageTitle":"Jeju Cruise Shore Excursion Bus Tour | East or South Route by Port | AtoC Korea","metaDescription":"A Jeju shore excursion bus tour designed for cruise passengers. Route changes by docking port: Jeju Port guests visit Seongsan Ilchulbong, Seopjikoji, Seongeup Folk Village, and Dongmun Market, while Gangjeong Port guests visit 1100 Highland, Jusangjeolli Cliff, Cheonjiyeon Falls, and Seogwipo Olle Market."},"catalog_card":{"slug":"jeju-cruise-shore-excursion-bus-tour","title":"Jeju Cruise Shore Excursion Bus Tour","subtitle":"Port-based East or South Jeju sightseeing built around your ship’s actual docking and departure window.","region":"East Jeju or South Jeju","duration":"Ship-synced shore excursion","stopsCount":4,"rating":0,"reviewCount":0,"badges":["Cruise Passenger Friendly","Port-Based Smart Routing","Return-To-Ship Focused"],"heroImage":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","thumbnail":"https://api.cdn.visitjeju.net/photomng/thumbnailpath/202409/20/b9661064-af2f-4197-aef0-d3d44bf6c2b5.webp","priceLabel":"From US$59 per person","shortCardDescription":"A shore excursion bus tour for cruise guests arriving at either Jeju Port or Seogwipo Gangjeong Cruise Port. The east route focuses on Jeju’s UNESCO and heritage icons, while the south route favors mountain views, cliffs, waterfalls, and a traditional market finish."},"headlineLine1":"Jeju Cruise Shore Excursion","headlineLine2":"East or South Route by Port","price":{"amountLabel":"59","currency":"USD","per":"person"},"sql_overrides":{"tours":{"price":59}},"hero":{"imageUrl":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","imagePosition":"center 46%","tagline":"Built for cruise timing rather than generic day-tour timing, this Jeju shore excursion adjusts its route by docking port and aims to return you comfortably before all-aboard time.","pills":["Cruise Shore Excursion","Port-Based Routing","Admission Included"],"meta":{"duration":"Varies by port call","region":"East or South Jeju","stops":"4 stops per route","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"ship","label":"Tour Style","value":"Cruise Shore Excursion"},{"icon":"map","label":"Routing","value":"Varies by Docking Port"},{"icon":"camera","label":"Photo Potential","value":"High"},{"icon":"clock-3","label":"Timing Logic","value":"Ship-Synced"},{"icon":"ticket","label":"Admission Fees","value":"Included"},{"icon":"utensils-crossed","label":"Lunch","value":"Not Included"}],"galleryItems":[{"id":1,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","location":"Seongsan Ilchulbong","atmosphere":"Jeju’s strongest UNESCO-facing visual payoff for cruise guests docking on the north side","alt":"Seongsan Ilchulbong for an east Jeju cruise shore excursion"},{"id":2,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202311/22/c42559a5-c909-4603-ae16-24c2e03893a0.webp","location":"Gangjeong Cruise Port","atmosphere":"A south-side port base that naturally connects to Jungmun and central Seogwipo","alt":"Gangjeong cruise port for a Jeju shore excursion"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=1200&q=80","location":"Seopjikoji","atmosphere":"Open coastal walking with long sea views and a clear eastern Jeju feel","alt":"Coastal scenery similar to Seopjikoji in Jeju"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","location":"Jusangjeolli Cliff","atmosphere":"A classic volcanic-coast stop with strong visual reward in a short visit window","alt":"Basalt cliff scenery similar to Jusangjeolli on Jeju Island"}],"itineraryStops":[{"number":1,"time":"Varies","duration":"Port-based","name":"Jeju Port Route","category":"East Jeju UNESCO and Heritage Route","description":"When your ship docks at Jeju Port on the north side, the route heads east. It focuses on Seongsan Ilchulbong, Seopjikoji, Seongeup Folk Village, and Dongmun Market, which is a logical finish near the old city and port return corridor.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202409/20/c8bf6191-832c-4605-a948-96f07f6112d2.webp","highlights":["Best fit for Jeju Port dockings","Strong UNESCO and first-time Jeju landmark appeal","Mix of nature, heritage, and market browsing","Meal or snack time is usually built around Seongsan or Dongmun depending on timing"],"timeUsed":["Meet at terminal after disembarkation","Drive east for the main scenic block","Finish near the old-city market area before port return"],"whyOnRoute":"From Jeju Port, an eastern route gives stronger sightseeing density than crossing all the way south and back during a cruise call.","visitBasics":{"hours":"Adjusted to the ship’s actual call time","closed":"Some attraction schedules vary by season and operating conditions","admission":"Included","walking":"Moderate overall, with the strongest climb at Seongsan Ilchulbong"},"convenience":{"restroom":"Available at major attractions and market areas","parking":"Cruise coach access planned around each stop"},"smartNotes":{"photo":"This route gives the strongest east-side photo mix: crater, cape, thatched village details, and market atmosphere.","facilities":"Facilities are straightforward at the main attractions, with the most food flexibility near Seongsan and Dongmun.","tip":"The climb at Seongsan is the one stop that changes the route’s physical feel the most."}},{"number":2,"time":"Varies","duration":"Port-based","name":"Gangjeong Port Route","category":"South Jeju Scenic Route","description":"When your ship docks at Seogwipo Gangjeong Cruise Port on the south side, the route stays south and southwest. It connects 1100 Highland, Jusangjeolli Cliff, Cheonjiyeon Falls, and Seogwipo Olle Market for a compact but visually strong shore excursion.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202311/22/c42559a5-c909-4603-ae16-24c2e03893a0.webp","highlights":["Best fit for Gangjeong dockings","Mountain, cliff, waterfall, and market variety in one route","Good visual payoff without an extremely long transfer pattern","Food and snack time usually works best around Olle Market"],"timeUsed":["Meet at terminal after disembarkation","Run a scenery-focused south route with manageable transfers","Return to the port with buffer before all-aboard"],"whyOnRoute":"From Gangjeong Port, staying in the south avoids wasting a cruise call on long cross-island mileage and gives a more reliable return buffer.","visitBasics":{"hours":"Adjusted to the ship’s actual call time","closed":"Some attraction schedules vary by season and weather","admission":"Included","walking":"Easy to moderate overall"},"convenience":{"restroom":"Available at major attractions and market areas","parking":"Cruise coach access planned around each stop"},"smartNotes":{"photo":"This route leans into broad viewpoints, cliff geometry, water, and a lively local-market ending.","facilities":"Olle Market is the strongest stop for flexible food and souvenir time.","tip":"1100 Highland is the most weather-sensitive scenic stop on this route."}}],"routeFlowStops":[{"id":"01","name":"Cruise Terminal","theme":"Meet"},{"id":"02","name":"Port-Based Route","theme":"Scenery"},{"id":"03","name":"Market / Meal Window","theme":"Flexible"},{"id":"04","name":"Return to Port","theme":"Ship Buffer"}],"routePhases":[{"label":"Start","range":"1","theme":"Meet After Docking","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"Middle","range":"2-3","theme":"Port-Based Scenic Route","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"},{"label":"Finish","range":"4","theme":"Return Buffer","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"}],"routeShapeIntro":{"title":"How the excursion works","subtitle":"This is not a generic fixed-time day tour. The departure is usually set for around one hour after docking, and return is usually targeted for around one hour before your ship’s departure. If the ship departs late at night, operational planning aims for return by around 19:00."},"whyTourWorks":{"bestFor":["Cruise passengers wanting a reliable Jeju overview","First-time visitors to Jeju","Couples","Adult families","Travelers who want admission included and terminal-based meeting"],"lessIdeal":["Guests wanting a slow luxury private pace","Travelers avoiding stairs or uphill walking entirely","Visitors hoping to combine east and south Jeju in one short cruise call","Anyone wanting a fully indoor rainy-day itinerary"],"routeLogicSections":[{"title":"Why cruise guests need a different route logic","icon":"ship","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"The route is chosen by port, not just by popularity","detail":"Jeju has two cruise ports on different sides of the island, so the smartest shore excursion is the one that matches the docking side rather than forcing a long cross-island detour."},{"label":"Return buffer matters as much as sightseeing value","detail":"The product is designed around the ship’s call window, with return generally planned about one hour before departure rather than squeezing in one more risky stop."},{"label":"Admission is included to reduce friction on a short call","detail":"For cruise timing, it is more efficient to keep major sightseeing entry simple rather than asking guests to sort tickets on site."}]},{"title":"How the walking load actually feels","icon":"footprints","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"The Jeju Port route is more physically uneven","detail":"Seongsan Ilchulbong is the most demanding stop in either route because of its uphill climb and stairs, while the other east-side stops feel lighter."},{"label":"The Gangjeong route is steadier overall","detail":"1100 Highland, Jusangjeolli, Cheonjiyeon, and Olle Market usually feel more evenly manageable than a route anchored by Seongsan."},{"label":"Both routes are still sightseeing-first, not trekking-first","detail":"Even when there is some walking, the product is designed as a shore excursion with manageable stop lengths rather than a hiking tour."}]},{"title":"When timing shifts on cruise days","icon":"clock-3","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"Disembarkation speed can move departure earlier or later","detail":"The scheduled bus departure is usually set around one hour after docking, but actual movement can change if guests clear the ship earlier or terminal flow runs slower."},{"label":"Weather affects scenic stops differently by route","detail":"The east route is most exposed at Seopjikoji and Seongsan, while the south route is most exposed at 1100 Highland and Jusangjeolli."},{"label":"Meal time is flexible rather than fixed","detail":"Lunch is not included, and free time to eat is usually arranged at Seongsan, Dongmun Market, or Olle Market depending on the route and the day’s timing."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"Terminal Meeting and Return","preview":"2 cruise terminals, inside-terminal meeting, same-port return","content":["Jeju Port meeting point: inside Jeju Port International Passenger Terminal, near the arrival hall exit","Gangjeong meeting point: inside Seogwipo Gangjeong Cruise Terminal, near the arrival hall exit","Please look for the tour sign shown in your pre-arrival message","Final meeting details are usually reconfirmed about 4 days before arrival","Departure is usually planned for around 1 hour after the ship docks","Return is usually planned for around 1 hour before the ship departs","For late-night departures, operational planning usually aims for return by around 19:00","Return drop-off is at the same terminal where your ship is docked"]},{"id":"walking","title":"Walking and Terrain","preview":"Moderate overall, but route difficulty changes by port","content":["Jeju Port route: Seongsan Ilchulbong is the most demanding stop because of the uphill path and stairs","Jeju Port route: Seopjikoji, Seongeup Folk Village, and Dongmun Market are easier than Seongsan","Gangjeong route: 1100 Highland is light walking, Jusangjeolli and Cheonjiyeon are easy to moderate, and Olle Market is easy","Comfortable walking shoes are strongly recommended for both routes"]},{"id":"weather","title":"Weather and Cruise-Day Adjustments","preview":"Port timing and weather can affect pacing, stop order, or stay length","content":["Light rain: the excursion usually still operates","Strong wind or reduced visibility can shorten exposed scenic stops","Cruise disembarkation flow and road traffic may affect exact departure and return timing","If a stop becomes unsafe or operationally unsuitable, the guide may adjust stay length or stop order to protect return-to-ship timing"]},{"id":"money","title":"Payments and On-the-Day Spending","preview":"Cards are widely accepted, but some market vendors may still prefer cash","content":["Most shops accept credit cards","Some street-food stalls and traditional market vendors may prefer cash","A currency exchange machine may be available near the terminal exit, but lines can be long","A physical passport may be required if you need to exchange currency"]},{"id":"included","title":"What’s Included / Not Included","preview":"Guide, driver, transport, parking, tolls, fuel, and attraction admission included","variant":"included","content":["Professional English-speaking guide","Shared bus transportation","Driver fee","Fuel fees","Toll fees","Parking fees","Admission to attractions","Lunch is not included","Tips are not included","Personal food, shopping, and market purchases are not included"]}],"bookingTrustItems":[{"icon":"check-circle","title":"Port-based meet & return","description":"Jeju Port or Gangjeong — timing aligned to ship schedule","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Route matches your port","description":"East or south itinerary selected for your docking point","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Shore-excursion bus","description":"Efficient coverage in limited port time","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"預訂時（重要）","title":"留下您實際在用的聯絡方式","detail":"請填寫手機、WhatsApp、Line（ID 或加好友連結）。下船時間常臨近才公布，能隨時聯絡到的號碼很重要。"},{"timing":"預訂後","title":"確認信","detail":"您會先收到預訂確認信，含港口、行程、價格與岸上觀光概要。"},{"timing":"出發前一日（或郵輪時刻確定後）","title":"導遊直接聯絡","detail":"出發前一天，或郵輪抵離時間更明確時，導遊會以 WhatsApp、Line 或電話說明港口集合、下船與登船之銜接及最後細節。"},{"timing":"當天","title":"郵輪碼頭","detail":"請依約定地點與時間集合。岸上時間有限，團體巴士行程緊湊，導遊會保留安全回船緩衝。"},{"timing":"結束後","title":"回船與後續協助","detail":"於碼頭或約定下車處回船。若下船觀光後需協助，請傳訊息聯絡。"}],"practicalWeatherStatic":{"today":{"temp":"—","label":"Live weather integration"},"tomorrow":{"temp":"—","label":"Updated daily"}},"seasonalVariations":[{"name":"Spring","icon":"flower","description":"Clearer skies and softer temperatures usually help both routes, especially Seopjikoji, Seongsan, and the south-coast scenic stops.","tag":"Balanced season","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"Summer","icon":"sun","description":"The routes stay scenic, but heat and humidity can make exposed coastal stops feel more demanding than they look on paper.","tag":"Brighter but hotter","bgClass":"bg-summer","iconColor":"text-yellow-500"},{"name":"Autumn","icon":"leaf","description":"Autumn usually gives some of the cleanest sightseeing conditions for shore excursions, especially when visibility is good at 1100 Highland and Seongsan.","tag":"Best all-round season","bgClass":"bg-autumn","iconColor":"text-orange-500"},{"name":"Winter","icon":"snowflake","description":"Winter light can be beautiful, but wind and visibility affect the route more strongly, especially at 1100 Highland, Seopjikoji, and Seongsan.","tag":"Weather-sensitive","bgClass":"bg-winter","iconColor":"text-sky-500"}],"faqItems":[{"q":"How is the route decided?","a":"The route depends on your ship’s docking port. Ships docking at Jeju Port use the east route, while ships docking at Seogwipo Gangjeong Cruise Port use the south route."},{"q":"What time does the tour start and end?","a":"Departure is usually planned for around one hour after docking, and return is usually planned for around one hour before departure. For late-night sailings, planning usually targets a return by around 19:00."},{"q":"Is lunch included?","a":"No. Lunch is not included. Free time to eat is usually arranged at Seongsan, Dongmun Market, or Olle Market depending on the route and timing."},{"q":"Are attraction tickets included?","a":"Yes. Admission to attractions is included in the tour fee for this shore excursion product."},{"q":"What if my ship is delayed or terminal flow is slow?","a":"Cruise-day operations are handled around the actual ship schedule, terminal flow, and road conditions. The guide may adjust timing or stay length to protect the return-to-ship buffer."}],"reviewsPreview":{"averageRating":0,"totalReviews":0,"highlights":[],"featured":[]},"stickyBooking":{"price":{"amountLabel":"59","currency":"USD","per":"person"}},"routeVariants":[{"variant_id":"jeju_port_east_route","title":"Jeju Port East Route","dockingPort":{"name":"Jeju Port International Passenger Terminal","address":"191, Imhang-ro, Jeju-si, Jeju-do","meetingPoint":"Inside the terminal, near the arrival hall exit","pickupWindow":"Usually around 1 hour after docking","returnPolicy":"Usually around 1 hour before departure"},"summary":"The north-port route is built for cruise guests docking in Jeju City. It moves east for the strongest UNESCO-facing stop mix, then finishes with market time closer to the port-side urban area.","stops":[{"number":1,"name":"Seongsan Ilchulbong (Sunrise Peak)","category":"UNESCO Landmark","duration":"90 min","description":"Seongsan Ilchulbong is the flagship stop on the Jeju Port route. It is the most iconic east-side landmark and the strongest single stop for first-time visitors who want a clear Jeju highlight rather than a minor viewpoint.","highlights":["UNESCO World Natural Heritage landmark","The route’s strongest iconic sightseeing stop","High visual payoff for cruise guests with limited time","Most physically demanding stop on this route"],"visitBasics":{"hours":"Seasonal hours vary; tickets close before summit closing time","closed":"Closed on the first Monday of each month or the next day if Monday is a public holiday","admission":"Included","walking":"Moderate to challenging uphill with stairs"}},{"number":2,"name":"Seopjikoji","category":"Coastal Cape Walk","duration":"40 min","description":"Seopjikoji adds a clean, open coastal contrast after Seongsan. It works especially well on cruise tours because the scenery reads quickly and clearly without needing a long museum-style visit.","highlights":["Open sea views with Seongsan-facing coastal atmosphere","Short but photogenic stop","Good visual contrast after the volcanic cone stop","Weather exposure is the main comfort variable"],"visitBasics":{"hours":"Open area; operations can vary by day and weather","closed":"Open year-round","admission":"Included","walking":"Easy to moderate"}},{"number":3,"name":"Seongeup Folk Village","category":"Living Heritage Village","duration":"45 min","description":"Seongeup brings traditional Jeju stone-wall lanes, thatched-roof houses, and living heritage into the route. It gives the east course a cultural anchor rather than making it purely scenic.","highlights":["Important Folklore Cultural Heritage site","A living village rather than a purely staged museum setting","Adds cultural balance to a landmark-heavy route","Good for storytelling about old Jeju life"],"visitBasics":{"hours":"Open village environment; local business hours vary","closed":"Open year-round","admission":"Included","walking":"Easy"}},{"number":4,"name":"Dongmun Traditional Market","category":"Traditional Market and Flexible Meal Stop","duration":"60 min","description":"Dongmun Market is the logical finish for Jeju Port calls because it combines snack or light meal flexibility, souvenir browsing, and easy access back toward the port-side urban area.","highlights":["Jeju’s largest and oldest permanent market","Flexible stop for food, snacks, and souvenirs","Good last-stop energy before returning to the ship","A practical urban finish for north-port calls"],"visitBasics":{"hours":"Open year-round; individual vendor hours vary","closed":"Open year-round","admission":"Included","walking":"Easy"}}],"matching_profile_override":{"region_type":"east","region_tags":["jeju_east","seongsan","seopjikoji","seongeup","jeju_city_market","cruise_port_jeju"],"theme_tags":["unesco","volcanic_landmark","coast","heritage_village","traditional_market","first_time_friendly"],"pace_level":4,"walking_level":3,"scenic_level":5,"photo_level":5,"culture_level":4,"rain_fit":2,"iconic_landmark_fit":5,"shopping_fit":4}},{"variant_id":"gangjeong_port_south_route","title":"Gangjeong Port South Route","dockingPort":{"name":"Seogwipo Gangjeong Cruise Terminal","address":"261, Maljil-ro, Seogwipo-si, Jeju-do","meetingPoint":"Inside the terminal, near the arrival hall exit","pickupWindow":"Usually around 1 hour after docking","returnPolicy":"Usually around 1 hour before departure, or around 19:00 for late-night sailings"},"summary":"The south-port route stays efficient by focusing on 1100 Highland, Jungmun scenery, central Seogwipo waterfall atmosphere, and a market finish close to the south-side urban core.","stops":[{"number":1,"name":"1100 Highland","category":"Hallasan Viewpoint","duration":"35 min","description":"1100 Highland works well for Gangjeong arrivals because it gives a Hallasan-side visual change without turning the day into a mountain hike. It is light in walking but highly weather-dependent.","highlights":["One of Jeju’s best drive-up Hallasan viewpoints","Short stop with strong visual reward on clear days","Good contrast to later coast and waterfall stops","Most weather-sensitive stop on this route"],"visitBasics":{"hours":"08:30–18:00 (subject to change)","closed":"Open year-round","admission":"Included","walking":"Easy"}},{"number":2,"name":"Jusangjeolli Cliff","category":"Basalt Cliff Landmark","duration":"40 min","description":"Jusangjeolli is one of the best short scenic stops for a cruise-format bus tour. The volcanic rock columns and sea backdrop make the visual payoff immediate and easy to understand even in a short visit window.","highlights":["One of Jeju’s signature volcanic coastal sights","High photo payoff in a short stop","Strong first-time landmark value","Exposure to wind is the key comfort variable"],"visitBasics":{"hours":"09:00–17:30","closed":"Open year-round","admission":"Included","walking":"Easy to moderate"}},{"number":3,"name":"Cheonjiyeon Falls","category":"Waterfall Walk","duration":"45 min","description":"Cheonjiyeon adds a greener and softer mid-route rhythm after mountain and coastal scenery. The paved approach and famous waterfall basin make it one of the more broadly accessible scenic stops.","highlights":["Classic Seogwipo waterfall stop","Easy scenic path with strong atmosphere","Suitable for many mixed-age groups","A calmer contrast to cliff and viewpoint stops"],"visitBasics":{"hours":"Open until 22:00; daytime operations apply to most tour visits","closed":"Open year-round","admission":"Included","walking":"Easy"}},{"number":4,"name":"Seogwipo Maeil Olle Market","category":"Traditional Market and Flexible Food Stop","duration":"60 min","description":"Olle Market works especially well as the closing stop on the Gangjeong route because it combines food flexibility, souvenir browsing, and a lively local finish before the return drive to the terminal.","highlights":["Seogwipo’s most iconic permanent traditional market","Good for snacks, light meals, and local treats","A practical last stop for south-port calls","Less physically demanding than the earlier scenic stops"],"visitBasics":{"hours":"Open year-round; night-market activity starts later in the day","closed":"Open year-round","admission":"Included","walking":"Easy"}}],"matching_profile_override":{"region_type":"south","region_tags":["jeju_south","jungmun","seogwipo","gangjeong","olle_market","cruise_port_gangjeong"],"theme_tags":["hallasan_viewpoint","basalt_cliff","waterfall","traditional_market","scenic_route","first_time_friendly"],"pace_level":4,"walking_level":2,"scenic_level":5,"photo_level":5,"culture_level":2,"rain_fit":2,"iconic_landmark_fit":4,"shopping_fit":4}}],"matching_profile":{"product_id":"jeju-cruise-shore-excursion-bus-tour","product_type":"bus","route_type":"fixed_route","region_type":"any","region_tags":["jeju_cruise","jeju_port","gangjeong_port","jeju_east","jeju_south","port_based_routing"],"theme_tags":["shore_excursion","cruise_friendly","iconic_landmarks","market_finish","first_time_friendly","admission_included"],"poi_tags":["seongsan_ilchulbong","seopjikoji","seongeup_folk_village","dongmun_market","1100_highland","jusangjeolli_cliff","cheonjiyeon_falls","seogwipo_olle_market"],"pace_level":4,"walking_level":3,"scenic_level":5,"photo_level":5,"culture_level":3,"relax_level":2,"first_time_fit":5,"family_fit":4,"senior_fit":3,"couple_fit":4,"active_traveler_fit":4,"one_day_fit":5,"same_day_flight_fit":1,"rain_fit":2,"value_for_money_fit":5,"iconic_landmark_fit":5,"cafe_fit":1,"adult_family_fit":4,"young_kids_fit":3,"senior_active_fit":4,"senior_general_fit":3,"mobility_friendly_fit":2,"stroller_fit":2,"indoor_ratio":12,"weather_sensitivity":4,"local_culture_fit":3,"shopping_fit":4,"storytelling_fit":4,"comfort_level":3,"budget_fit":5,"premium_fit":1,"small_group_fit":1,"private_fit":1,"bus_fit":5,"price_band":"budget","pickup_base":"cruise_terminal","return_time_band":"ship_synced","duration_band":"port_call_synced","min_recommended_age":6,"hard_constraints":{"avoidIf":["very_short_port_call","travelers_needing_a_fully_indoor_route"],"notIdealFor":["very_low_mobility","travelers_avoiding_stairs_entirely","guests_wanting_to_mix_east_and_south_in_one_call"]},"walking_notes":["The product is sightseeing-first, but physical feel changes by docking port.","The Jeju Port route is more demanding because Seongsan Ilchulbong includes uphill walking and stairs.","The Gangjeong route is steadier overall, with easier walking at Olle Market and 1100 Highland.","Comfortable walking shoes are strongly recommended for cruise-day pacing."],"keywords":["jeju cruise shore excursion","jeju port shore excursion bus tour","gangjeong port shore excursion","jeju cruise excursion seongsan seopjikoji","jeju cruise excursion jusangjeolli cheonjiyeon","jeju cruise bus tour admission included","jeju cruise terminal pickup tour","jeju shore excursion east route","jeju shore excursion south route","jeju cruise market stop tour"],"synonym_hints":["cruise passenger jeju day tour","shore excursion from jeju port","shore excursion from gangjeong port","return to ship jeju excursion","jeju cruise port sightseeing tour","port-based jeju bus excursion"],"profile_version":1,"is_active":true},"matching_metadata":{"matching_schema":"tour_matching_profiles_embedded_v1","embedded_for":["authoring","review","sql_backfill_reference"],"note":"Scores were tuned for a cruise shore-excursion format where return-to-ship safety and port-based routing matter as much as sightseeing quality. Walking and weather fit were kept conservative because the Jeju Port route includes Seongsan Ilchulbong and both routes include exposed outdoor stops.","duration_hours":null,"stop_count":4},"pickup_dropoff":{"pickupType":"fixed_meeting_points","dropoffType":"same_terminal_return","departure":[{"order":1,"name":"Jeju Port International Passenger Terminal","type":"cruise_terminal","note":"Meet inside the terminal near the arrival hall exit. Departure is usually about 1 hour after docking."},{"order":2,"name":"Seogwipo Gangjeong Cruise Terminal","type":"cruise_terminal","note":"Meet inside the terminal near the arrival hall exit. Departure is usually about 1 hour after docking."}],"return":[{"order":1,"name":"Jeju Port International Passenger Terminal","type":"cruise_terminal","note":"Used when the ship is docked at Jeju Port."},{"order":2,"name":"Seogwipo Gangjeong Cruise Terminal","type":"cruise_terminal","note":"Used when the ship is docked at Seogwipo Gangjeong."}],"notes":["The exact terminal used depends on your ship’s docking port.","Final sign and meeting guidance is usually reconfirmed about 4 days before arrival.","Return is planned with a ship-safety buffer rather than at the last possible minute.","If the sailing departs late at night, planning usually aims for return by around 19:00."]}}'::jsonb
)
